proof_block:
// Bind each run's pieces to fresh short ghost names so z3 has two distinct,
// per-run terms to hang triggers on instead of two structurally identical
// `next_ensures(pre_self_, pre_netc, ..., ri)` applications.
let er1 = (r1.1)@;
let er2 = (r2.1)@;
let ok1 = r1.0;
let ok2 = r2.0;

// Unfold `HostState::next_ensures` for each run as a stand-alone implication.
// `next_ensures` is `open spec` so Verus can verify each of these by simple
// unfolding; the value is that z3 then sees individual conjuncts indexed by
// `er1`/`er2` rather than buried inside two identical opaque applications.
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
        ==> (ok1 == post1_netc.ok())
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
        ==> (ok2 == post2_netc.ok())
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
        ==> er1.well_typed_events()
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
        ==> er2.well_typed_events()
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
        ==> (ok1 ==> er1.event_seq() == er1.ios)
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
        ==> (ok2 ==> er2.event_seq() == er2.ios)
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
        ==> ((ok1 || er1.sends.len() > 0)
                ==> post1_netc.history() == pre_netc.history() + er1.event_seq())
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
        ==> ((ok2 || er2.sends.len() > 0)
                ==> post2_netc.history() == pre_netc.history() + er2.event_seq())
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post1_self_, post1_netc, r1)
        ==> (ok1 ==> HostState::next(pre_self_.view(), post1_self_.view(), er1.ios))
);
assert(
    HostState::next_ensures(pre_self_, pre_netc, post2_self_, post2_netc, r2)
        ==> (ok2 ==> HostState::next(pre_self_.view(), post2_self_.view(), er2.ios))
);

// Trigger-aligned instantiations of the three per-index quantifiers inside
// `well_typed_events`, separately per run. `well_typed_events` is `open
// spec`, so Verus unfolds for free and the empty `by {}` body suffices. The
// explicit `#[trigger]` on `er1.sends[i]` / `er2.sends[i]` etc. gives z3
// matching trigger patterns for both runs.
assert forall|i: int|
    er1.well_typed_events() && 0 <= i < er1.sends.len()
    implies (#[trigger] er1.sends[i]) is Send by {};
assert forall|i: int|
    er2.well_typed_events() && 0 <= i < er2.sends.len()
    implies (#[trigger] er2.sends[i]) is Send by {};
assert forall|i: int|
    er1.well_typed_events() && 0 <= i < er1.recvs.len()
    implies (#[trigger] er1.recvs[i]) is Receive by {};
assert forall|i: int|
    er2.well_typed_events() && 0 <= i < er2.recvs.len()
    implies (#[trigger] er2.recvs[i]) is Receive by {};
assert forall|i: int|
    er1.well_typed_events() && 0 <= i < er1.clocks.len()
    implies (#[trigger] er1.clocks[i]) is ReadClock || er1.clocks[i] is TimeoutReceive by {};
assert forall|i: int|
    er2.well_typed_events() && 0 <= i < er2.clocks.len()
    implies (#[trigger] er2.clocks[i]) is ReadClock || er2.clocks[i] is TimeoutReceive by {};
assert(er1.well_typed_events() ==> er1.clocks.len() <= 1);
assert(er2.well_typed_events() ==> er2.clocks.len() <= 1);

// Pull the EventResultsView equality the determinism predicate needs onto
// the per-component shape (recvs/clocks/sends/ios), so z3 can match on each
// component independently when reasoning about `er1.view() == er2.view()`.
assert(er1.view() == EventResultsView {
    recvs: er1.recvs, clocks: er1.clocks, sends: er1.sends, ios: er1.ios,
});
assert(er2.view() == EventResultsView {
    recvs: er2.recvs, clocks: er2.clocks, sends: er2.sends, ios: er2.ios,
});

// Same shape-flattening for NetClient view: expose the (history@, end_point)
// pair on both runs so the final `post1_netc.view() == post2_netc.view()`
// conjunct of `det_..._equal` reduces to two scalar equalities z3 can chase.
// CRITICAL: the closed `view()` body reads the Ghost field `self.history@`
// (a projection of the `Ghost<History>` field), NOT the unrelated
// `self.history()` external_body spec method. The prior attempt mixed those
// two and Verus correctly refused the assertion. We use `history@` here.
assert(post1_netc.view() == NetClientView {
    history: post1_netc.history@, end_point: post1_netc.end_point,
});
assert(post2_netc.view() == NetClientView {
    history: post2_netc.history@, end_point: post2_netc.end_point,
});
